import VideoRoot, {
  VideoViewport,
  VideoControls,
  VideoPlayTrigger,
  VideoProgressBar
} from "@/registry/8starlabs-ui/blocks/video-player";
import { cn } from "@/lib/utils";

function MyCustomPlayer({
  label,
  className,
  wrapperClassName
}: {
  label: string;
  className: string;
  wrapperClassName?: string;
}) {
  return (
    <div className={cn("min-w-0 space-y-2", wrapperClassName)}>
      <p className="text-center text-xs font-medium uppercase tracking-wider text-muted-foreground">
        {label}
      </p>
      <VideoRoot className={className}>
        <VideoViewport src="https://vjs.zencdn.net/v/oceans.mp4" fit="cover" />
        <VideoControls className="flex min-w-0 items-center justify-between gap-2">
          <VideoPlayTrigger />
          <VideoProgressBar className="min-w-0" />
        </VideoControls>
      </VideoRoot>
    </div>
  );
}

export default function VideoPlayerSizingDemo() {
  return (
    <div className="grid w-full min-w-0 max-w-full gap-6 p-4 md:grid-cols-2">
      <MyCustomPlayer
        label="aspect-video"
        className="aspect-video rounded-lg"
        wrapperClassName="md:col-span-2"
      />
      <MyCustomPlayer
        label="aspect-square"
        className="aspect-square rounded-lg"
      />
      <MyCustomPlayer label="fixed height" className="h-120 rounded-lg" />
    </div>
  );
}
